/**
 * CLI: read ArenaMergeGateInput JSON from a file or stdin, exit 0 iff evaluateArenaMergeGate passes.
 * Usage: pnpm exec tsx ./scripts/evaluate-arena-merge-gate.ts <path.json|->
 *
 * Input shape: { "verificationBundle": unknown, "cooling"?: { "state": CoolingState }, "rollbackReplay"?: { "policy", "samples" } }
 */
import * as fs from 'node:fs';
import {
  evaluateArenaMergeGate,
  type ArenaMergeGateInput,
} from '../src/arena-merge-gate';

function printUsage(): void {
  process.stderr.write(
    'Usage: pnpm exec tsx ./scripts/evaluate-arena-merge-gate.ts <gate-input.json|->\n' +
      '  JSON must include "verificationBundle"; optional "cooling", "rollbackReplay".\n'
  );
}

function main(): void {
  const path = process.argv[2];
  if (path === undefined || path === '--help' || path === '-h') {
    printUsage();
    process.exit(path === undefined ? 1 : 0);
  }

  const raw =
    path === '-' ? fs.readFileSync(0, 'utf8') : fs.readFileSync(path, 'utf8');
  let json: unknown;
  try {
    json = JSON.parse(raw) as unknown;
  } catch {
    process.stderr.write('evaluate-arena-merge-gate: invalid JSON\n');
    process.exit(1);
  }

  if (json === null || typeof json !== 'object') {
    process.stderr.write('evaluate-arena-merge-gate: expected JSON object\n');
    process.exit(1);
  }

  const o = json as Record<string, unknown>;
  if (!('verificationBundle' in o)) {
    process.stderr.write(
      'evaluate-arena-merge-gate: missing required field verificationBundle\n'
    );
    process.exit(1);
  }

  const input: ArenaMergeGateInput = {
    verificationBundle: o['verificationBundle'],
    ...(o['cooling'] !== undefined
      ? { cooling: o['cooling'] as ArenaMergeGateInput['cooling'] }
      : {}),
    ...(o['rollbackReplay'] !== undefined
      ? {
          rollbackReplay:
            o['rollbackReplay'] as ArenaMergeGateInput['rollbackReplay'],
        }
      : {}),
  };

  const r = evaluateArenaMergeGate(input);
  if (!r.ok) {
    process.stderr.write(
      `evaluate-arena-merge-gate: blocked: ${r.reasons.join(', ')}\n`
    );
    process.exit(1);
  }
  process.stdout.write('evaluate-arena-merge-gate: ok\n');
  process.exit(0);
}

main();
